/****** Objeto: StoredProcedure [dbo].[_pa_mantenimiento_Autorizacion] Fecha de script: 18/05/2026 10:08:31 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
create   procedure [dbo].[_pa_mantenimiento_Autorizacion]
@CODIGO_AUTORIZACION			int=null,
@CODIGO_FORMULARIO				int=null,
@CODIGO_PERSONAL				int=null,
@APROBACION_AUTORIZACION		bit=null,

@Opcion							char(1),

@pRpta							int output,
@pMensaje						varchar(100) output
as
  
if (@Opcion='N')
    Begin
	       declare @CANTIDAD_REGISTROS	int
		   SELECT  @CANTIDAD_REGISTROS = COUNT(*) 
                   FROM  dbo.autorizacion INNER JOIN
                         dbo.formulario ON dbo.autorizacion.id_formulario = dbo.formulario.id_formulario
                         WHERE (dbo.autorizacion.IDPer = @CODIGO_PERSONAL) AND (dbo.formulario.id_formulario = @CODIGO_FORMULARIO)

		   if (@CANTIDAD_REGISTROS>0)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Usuario ya tiene autorizacion asignada.'
				   return 0
			   End
		   insert into dbo.autorizacion values
                                 ( @CODIGO_FORMULARIO,
								   @CODIGO_PERSONAL,
								   @APROBACION_AUTORIZACION	
								 )
			if (@@RowCount=1) 
			   Begin
			    
				set @pRpta=@@IDENTITY
				set @pMensaje='Datos de AUTORIZACION se guardaron satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0   
				set @pMensaje='Datos de AUTORIZACION no se guardaron.'
			   End
	 End
else if (@Opcion='M')
    Begin
           if(@CODIGO_AUTORIZACION=-1 and @APROBACION_AUTORIZACION=1)
			   begin
			        SELECT  @CANTIDAD_REGISTROS = COUNT(*) 
                    FROM  dbo.autorizacion INNER JOIN
                         dbo.formulario ON dbo.autorizacion.id_formulario = dbo.formulario.id_formulario
                         WHERE (dbo.autorizacion.IDPer = @CODIGO_PERSONAL) AND (dbo.formulario.id_formulario = @CODIGO_FORMULARIO)

				   if (@CANTIDAD_REGISTROS>0)
					   Begin
						   set @pRpta=0
						   set @pMensaje='Usuario ya tiene autorizacion asignada.'
						   return 0
					   End
					insert into dbo.autorizacion values
									 ( @CODIGO_FORMULARIO,
									   @CODIGO_PERSONAL,
									   @APROBACION_AUTORIZACION	
									 )
					if (@@RowCount=1) 
					   Begin
			    
						set @pRpta=@@IDENTITY
						set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
					   End
					else
					   Begin
						set @pRpta=0   
						set @pMensaje='Datos de AUTORIZACION no se modificaron.'
					   End
			   end
		   else if(@CODIGO_AUTORIZACION<>-1 and @APROBACION_AUTORIZACION=0)
		       begin
			        BEGIN TRY
							delete from dbo.permiso where id_autorizacion=@CODIGO_AUTORIZACION
							delete from dbo.autorizacion where id_autorizacion=@CODIGO_AUTORIZACION
							if (@@RowCount=1) 
							   Begin
									set @pRpta=1
									set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
							   End
							else
							   Begin
									set @pRpta=0   
									set @pMensaje='Datos de AUTORIZACION no se modificaron.'
							   End
                    END TRY 
					BEGIN CATCH
							set @pRpta=0   
							set @pMensaje='Datos de AUTORIZACION no se modificaron.'
					END CATCH; 
			   end
           else if(@CODIGO_AUTORIZACION<>-1 and @APROBACION_AUTORIZACION=1)
		       begin
					update dbo.autorizacion
					set aprobacion_autorizacion = @APROBACION_AUTORIZACION	                								   
					where id_autorizacion = @CODIGO_AUTORIZACION and id_formulario = @CODIGO_FORMULARIO and IDPer = @CODIGO_PERSONAL
			       if (@@RowCount=1) 
					   Begin
							set @pRpta=1
							set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
					   End
					else
					   Begin
							set @pRpta=0   
							set @pMensaje='Datos de AUTORIZACION no se modificaron.' 
					   End
			   end
	 End
	 
	 





GO
