create   procedure [dbo].[_pa_mantenimiento_Permiso]
@CODIGO_PERMISO						int=null,
@CODIGO_AUTORIZACION			    int=null,
@DERECHO							VARCHAR(MAX)=null,
@APROBACION_PERMISO					bit=null,

@Opcion							char(1),

@pRpta							int output,
@pMensaje						varchar(100) output
as
  
if (@Opcion='N')
    Begin
	       if([dbo].[_obtner_codigo_derecho] (@DERECHO)=-1)
			   begin
					set @pRpta=0
					set @pMensaje='El Derecho - ' + @DERECHO + '- ingresado para generar Permiso(s) en la Autorizacion no existe.'
					return 0
			   end
		   insert into dbo.permiso values
                                 ( @CODIGO_AUTORIZACION,
                                   [dbo].[_obtner_codigo_derecho] (@DERECHO),
                                   @APROBACION_PERMISO
								  )
			if (@@RowCount=1) 
			   Begin
			    
				set @pRpta=1
				set @pMensaje='Datos de AUTORIZACION y PERMISOS se guardaron satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0   
				set @pMensaje='Datos de AUTORIZACION y PERMISOS no se guardaron.'
			   End
	 End
else if (@Opcion='M')
         Begin
				if(@CODIGO_PERMISO=-1 and @APROBACION_PERMISO=1)
					begin
						if([dbo].[_obtner_codigo_derecho] (@DERECHO)=-1)
						   begin
								set @pRpta=0
								set @pMensaje='El Derecho - ' + @DERECHO + '- ingresado para generar Permiso(s) en la Autorizacion no existe.'
								return 0
						   end
						   BEGIN TRY
								   insert into dbo.permiso values
														 ( @CODIGO_AUTORIZACION,
														   [dbo].[_obtner_codigo_derecho] (@DERECHO),
														   @APROBACION_PERMISO
														  )
									if (@@RowCount=1) 
									   Begin			    
											set @pRpta=1
											set @pMensaje='Datos de AUTORIZACION y PERMISOS se guardaron satisfactorimente.'
									   End
									else
									   Begin
											set @pRpta=0   
											set @pMensaje='Datos de AUTORIZACION y PERMISOS no se guardaron.'
									   End
						   END TRY
						   BEGIN CATCH
										set @pRpta=0   
										set @pMensaje='Datos de AUTORIZACION y PERMISOS no se guardaron.'
						   END CATCH; 
					end
				else if(@CODIGO_PERMISO<>-1 and @APROBACION_PERMISO=0)
					begin
						 BEGIN TRY
									if EXISTS(SELECT p.* FROM dbo.permiso AS p WHERE p.id_permiso = @CODIGO_PERMISO)
									   Begin
										    delete from dbo.permiso where id_permiso = @CODIGO_PERMISO and id_autorizacion = @CODIGO_AUTORIZACION and id_derecho = [dbo].[_obtner_codigo_derecho] (@DERECHO)
											if (@@RowCount=1) 
											   Begin
													 declare @CANTIDAD_REGISTROS	int
													 SELECT  @CANTIDAD_REGISTROS = COUNT(*) 
															 FROM dbo.autorizacion as a INNER JOIN
															 dbo.permiso as p ON a.id_autorizacion = p.id_autorizacion INNER JOIN
															 dbo.formulario as f ON a.id_formulario = f.id_formulario INNER JOIN
															 dbo.derecho as d ON p.id_derecho = d.id_derecho
													 GROUP BY a.id_autorizacion
													 HAVING  (a.id_autorizacion = @CODIGO_AUTORIZACION)
													 if (@CANTIDAD_REGISTROS>0)
														begin
															 set @pRpta=1
															 set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
														end
													 else
														begin
															 delete from dbo.autorizacion where id_autorizacion=@CODIGO_AUTORIZACION
															if (@@RowCount=1) 
															   Begin
																	set @pRpta=1
																	set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
															   End
															else
															   Begin
																	set @pRpta=0   
																	set @pMensaje='Datos de AUTORIZACION no se modificaron.'
															   End
														end    
											   End
											else
											   Begin
													set @pRpta=0   
													set @pMensaje='Datos de AUTORIZACION no se modificaron.'
											   End
									  End
								 Else
								      Begin
											set @pRpta=1
											set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
									  End
									
						 END TRY
						 BEGIN CATCH
									set @pRpta=0   
									set @pMensaje='Datos de AUTORIZACION no se modificaron.'
						 END CATCH; 						
					end
			   else if(@CODIGO_PERMISO<>-1 and @APROBACION_PERMISO=1)
					begin
						 if EXISTS(SELECT a.* FROM dbo.autorizacion as a WHERE a.id_autorizacion = @CODIGO_AUTORIZACION)
						    Begin
								 update dbo.permiso
								 set aprobacion_permiso = @APROBACION_PERMISO	                								   
								 where id_permiso = @CODIGO_PERMISO and id_autorizacion = @CODIGO_AUTORIZACION and id_derecho = [dbo].[_obtner_codigo_derecho] (@DERECHO)
								 if (@@RowCount=1) 
								    Begin
										 set @pRpta=1
										 set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
								    End
								 else
								    Begin
										 set @pRpta=0   
										 set @pMensaje='Datos de AUTORIZACION no se modificaron.'
								    End
							End	
						else
						    Begin
								 set @pRpta=1
								 set @pMensaje='Datos de AUTORIZACION se modificaron satisfactorimente.'
							End												
					end
	     End
		 
		 

				   
			   
			   
			      





GO
