create proc [dbo].[consultar_Acceso_formulario_autorizacion]
@CODIGO_PERSONAL  	    int

as
		
	
    
    
SELECT      a.id_autorizacion AS [COD AUTORIZACION],f.id_formulario AS [COD FORMULARIO], 
                         a.aprobacion_autorizacion AS AUTORIZACION, f.nombre_formulario AS [NOMBRE FORMULARIO]
FROM            dbo.autorizacion AS a INNER JOIN
                         dbo.formulario as f ON a.id_formulario = f.id_formulario
WHERE        (a.IDPer = @CODIGO_PERSONAL)
ORDER BY [NOMBRE FORMULARIO] asc





GO
/****** Objeto: StoredProcedure [dbo].[consultar_Acceso_formulario_permiso] Fecha de script: 18/05/2026 10:08:31 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO



create proc [dbo].[consultar_Acceso_formulario_permiso]
@CODIGO_PERSONAL  	    int,
@CODIGO_FORMULARIO      int

as
  
SELECT        a.IDPer          AS [COD PERSONAL],
              a.id_formulario  AS [COD FORMULARIO], 
              UPPER(RTRIM(LTRIM(d.nombre_derecho))) AS [DERECHO FORMULARIO],
			  p.aprobacion_permiso AS [APROBACION PERMISO],
			  P.id_permiso AS [COD PERMISO]
FROM          dbo.permiso as p INNER JOIN
              dbo.derecho as d ON p.id_derecho = d.id_derecho INNER JOIN
              dbo.autorizacion as a ON p.id_autorizacion = a.id_autorizacion
WHERE        (a.IDPer = @CODIGO_PERSONAL) AND (a.id_formulario = @CODIGO_FORMULARIO)
ORDER BY [DERECHO FORMULARIO] asc





GO
