/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_ConsultarComponenteCI]
@_Id_CI	    int=null
AS
BEGIN
	 
SELECT        TCEC.NOMBRE_TIPO_COMPONENTE AS NOMBRE, 
                         CEC.DESCRIPCION, CEC.FABRICANTE, 
                         CEC.NRO_SERIE AS [NRO SERIE], M.NOMBRE AS MARCA, 
                         MO.NOMBRE AS MODELO
FROM            dbo.COMPONENTES_ELEMENTO_CONFIGURACION as CEC INNER JOIN
                         dbo.TIPO_COMPONENTE_ELELEMENTO_CONFIGURACION AS TCEC ON 
                         CEC.ID_TIPO_COMPONENTE = TCEC.ID_TIPO_COMPONENTE
                          INNER JOIN
                         dbo.MARCA AS M ON CEC.ID_MAR = M.ID_MAR INNER JOIN
                         dbo.MODELO AS MO ON CEC.ID_MOD =MO.ID_MOD
WHERE        (CEC.ID_ELEMENTO_CONFIGURACION = @_Id_CI) order by TCEC.NOMBRE_TIPO_COMPONENTE asc

END

--exec  [dbo].[pr_ConsultarComponenteCI] 16




