--						 EC.FABRICANTE_O_PROVEEDOR AS [FABRICANTE / PROVEEDOR], --22
--                         M.NOMBRE AS MARCA, --23
--						 MO.NOMBRE AS MODELO, --24
--						 EC.IP as IP, --25
--						 EC.GATEWAY as GATEWAY, --26
--						 EC.GRUPO_TRABAJO AS [GRUPO TRABAJO]--27
--FROM            dbo.ELEMENTOS_CONFIGURACION AS EC INNER JOIN
--                         dbo.TIPOS_ELEMENTO_CONFIGURACION AS TEC ON EC.ID_TIPO = TEC.ID_TIPO INNER JOIN
--                         dbo.ESTADO_ELEMENTO_CONFIGURACION AS EEC ON EC.ID_ESTADO = EEC.ID_ESTADO INNER JOIN
--                         dbo.Personal AS P ON EC.PROPIETARIO = P.Id_Personal INNER JOIN
--                         dbo.[DESCRIPCION_ELEMENTO CONFIGURACION] AS DEC ON EC.ID_DESCRIPCION = DEC.ID_DESCRIPCION INNER JOIN
--                         dbo.IMPACTO_COMERCIAL_ELE_CONF_HAR AS ICEC ON EC.ID_IMP_ELE_CONF_HAR = ICEC.ID_IMP_ELE_CONF_HAR INNER JOIN
--                         dbo.Area AS A ON EC.LOCALIZACION_FISICA = A.Id_Area AND P.Id_Area = A.Id_Area INNER JOIN
--                         dbo.Local AS L ON A.Id_Local = L.Id_Local INNER JOIN
--                         dbo.Sede AS S ON L.Id_Sede = S.Id_Sede INNER JOIN
--                         dbo.Ubigeo AS U ON L.Cod_Ubi = U.Cod_Ubi INNER JOIN
--                         dbo.Usuario AS USU ON EC.RESPONSABLE_REGISTRO = USU.Id_Uusario INNER JOIN
--                         dbo.NIVEL_PRIORIDAD AS NP ON EC.ID_NIVEL = NP.ID_NIVEL INNER JOIN
--                         dbo.MARCA as M ON EC.ID_MAR = M.ID_MAR INNER JOIN
--						 dbo.MODELO as MO on EC.ID_MOD = MO.ID_MOD

SELECT        EC.ID_ELEMENTO_CONFIGURACION AS [ID CI], EC.NOMBRE_ELEMENTO_CONFIGURACION AS [NOMBRE CI], TEC.ID_TIPO AS [ID TIPO CI], TEC.NOMBRE_TIPO AS [NOMBRE TIPO CI], EEC.NOMBRE_ESTADO AS [ESTADO CI], 
                         P.Id_Personal AS [ID PROPIETARIO], P.Nombre_Personal + ' ' + P.ApePat_Personal + ' ' + P.ApeMat_Personal AS PROPIETARIO, DEC.NOMBRE_DESCRIPCION AS [DESCRIPCION CI], ICEC.NOMBRE AS [IMPACTO CI], 
                         S.Descripcion_Sede AS SEDE, L.Nombre_Local AS LOCAL, U.Distrito + '/ ' + U.Provincia + ' /' + U.Departamento AS [UBICACION LOCAL], L.Direccion_Local AS [DIRECCION LOCAL], A.Id_Area AS [ID AREA], 
                         A.Descripcion_Area AS AREA, A.Nro_Piso AS [NRO PISO], A.Nro_Ambiente AS [NRO AMBIENTE], EC.FECHA_REGISTRO AS [FEC. CREACION CI], EC.RESPONSABLE_REGISTRO AS [ID RESPONSABLE], 
                         USU.Nombre + ' ' + USU.ApePat + ' ' + USU.ApeMat AS RESPONSABLE, NP.NOMBRE_NIVEL AS [NIVEL PRIORIDAD], EC.NRO_SERIE AS [NRO. SERIE], EC.FABRICANTE_O_PROVEEDOR AS [FABRICANTE / PROVEEDOR], 
                         M.NOMBRE AS MARCA, MO.NOMBRE AS MODELO, EC.IP, EC.GATEWAY, EC.GRUPO_TRABAJO AS [GRUPO TRABAJO]
FROM            dbo.ELEMENTOS_CONFIGURACION AS EC INNER JOIN
                         dbo.TIPOS_ELEMENTO_CONFIGURACION AS TEC ON EC.ID_TIPO = TEC.ID_TIPO INNER JOIN
                         dbo.ESTADO_ELEMENTO_CONFIGURACION AS EEC ON EC.ID_ESTADO = EEC.ID_ESTADO INNER JOIN
                         dbo.Personal AS P ON EC.PROPIETARIO = P.Id_Personal INNER JOIN
                         dbo.[DESCRIPCION_ELEMENTO CONFIGURACION] AS DEC ON EC.ID_DESCRIPCION = DEC.ID_DESCRIPCION INNER JOIN
                         dbo.IMPACTO_COMERCIAL_ELE_CONF_HAR AS ICEC ON EC.ID_IMP_ELE_CONF_HAR = ICEC.ID_IMP_ELE_CONF_HAR INNER JOIN
                         dbo.Area AS A ON EC.LOCALIZACION_FISICA = A.Id_Area INNER JOIN
                         dbo.Local AS L ON A.Id_Local = L.Id_Local INNER JOIN
                         dbo.Sede AS S ON L.Id_Sede = S.Id_Sede INNER JOIN
                         dbo.Ubigeo AS U ON L.Cod_Ubi = U.Cod_Ubi INNER JOIN
                         dbo.Usuario AS USU ON EC.RESPONSABLE_REGISTRO = USU.Id_Uusario INNER JOIN
                         dbo.NIVEL_PRIORIDAD AS NP ON EC.ID_NIVEL = NP.ID_NIVEL INNER JOIN
                         dbo.MARCA AS M ON EC.ID_MAR = M.ID_MAR INNER JOIN
                         dbo.MODELO AS MO ON EC.ID_MOD = MO.ID_MOD
    WHERE EC.ID_ELEMENTO_CONFIGURACION=@_Id_CI	

END





