/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_ListaElementosConfiguracion_2]
@NOMBRE_CI					varchar(max)=null,
@TIPO_CI					varchar(max)=null,
@ESTADO_CI					varchar(max)=null,
@PROPIETARIO_CI					varchar(max)=null,
@DESCRIPCION_CI					varchar(max)=null,

@SEDE				varchar(max)=null,
@OCAL				varchar(max)=null,
@AREA				varchar(max)=null


AS
BEGIN
	 
    select * from VISTA_ELEMENTOS_CONFIGURACION_2
	WHERE   ([NOMBRE CI]='' or [NOMBRE CI] LIKE '%' +  @NOMBRE_CI + '%') AND
	([NOMBRE TIPO CI]='' or [NOMBRE TIPO CI] LIKE '%' +  @TIPO_CI + '%') and
	([ESTADO CI]='' or [ESTADO CI]LIKE '%' +  @ESTADO_CI + '%') and
	(PROPIETARIO='' or PROPIETARIO LIKE '%' +  @PROPIETARIO_CI + '%') and
	([DESCRIPCION CI]='' or [DESCRIPCION CI] LIKE '%' +  @DESCRIPCION_CI + '%') and
	(SEDE='' or SEDE LIKE '%' +  @SEDE + '%') and
	(LOCAL='' or LOCAL LIKE '%' +  @OCAL + '%') AND
	(AREA='' or AREA LIKE '%' +  @AREA + '%') and
	not ([NOMBRE TIPO CI]='EQUIPOS DE ESCRITORIO' OR  [NOMBRE TIPO CI]='LAPTOP'  OR  [NOMBRE TIPO CI]='IMPRESORA'
	OR  [NOMBRE TIPO CI]='ESCANER' OR  [NOMBRE TIPO CI]='DISPOSITIVOS DE RED' OR  [NOMBRE TIPO CI]='BASE DE DATOS'
	OR  [NOMBRE TIPO CI]='SERVICIO' OR  [NOMBRE TIPO CI]='MANUALES DE PROCESOS'  OR  [NOMBRE TIPO CI]='SERVIDORES')

END





