AS
BEGIN
	 
    select * from [dbo].[VISTA_CIs_COMPONENTES_ASIGNADOS]
	WHERE   ([NOMBRE CI]='' or [NOMBRE CI] LIKE '%' +  @NOMBRE_CI + '%') AND
	([NOMBRE TIPO CI]='' or [NOMBRE TIPO CI] LIKE '%' +  @TIPO_CI + '%') and
	([ESTADO CI]='' or [ESTADO CI]LIKE '%' +  @ESTADO_CI + '%') and
	(PROPIETARIO='' or PROPIETARIO LIKE '%' +  @PROPIETARIO_CI + '%') and
	([DESCRIPCION CI]='' or [DESCRIPCION CI] LIKE '%' +  @DESCRIPCION_CI + '%') and
	([IMPACTO CI]='' or [IMPACTO CI] LIKE '%' +  @IMPACTO_CI + '%') and
	(SEDE='' or SEDE LIKE '%' +  @SEDE + '%') and
	(LOCAL='' or LOCAL LIKE '%' +  @OCAL + '%') AND
	(AREA='' or AREA LIKE '%' +  @AREA + '%') AND
	([NRO SERIE]='' or [NRO SERIE] LIKE '%' +  @NRO_SERIE_CI + '%') AND
	 (MARCA='' or MARCA LIKE '%' +  @MARCA + '%') and
	 [NOMBRE TIPO CI] in ('SERVIDORES','EQUIPOS DE ESCRITORIO')
END





