/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_ListaUsuarios]

AS
BEGIN



						 SELECT        U.Id_Uusario AS ID, U.Nombre AS NOMBRE, U.ApePat AS APEPAT, U.ApeMat AS APEMAT, U.Telefono AS TELEFONO, U.Email AS EMAIL, U.Login AS LOGIN, 
                         U.Password AS PASSWORD, CASE u.Estado WHEN 1 THEN 'ACTIVO' ELSE 'INACTIVO' END AS ESTADO, c.NOMBRE_CARGO AS CARGO, 
                         S.Descripcion_Sede AS SEDE, L.Nombre_Local AS LOCAL, A.Descripcion_Area AS AREA
FROM            dbo.Usuario AS U INNER JOIN
                         dbo.CARGO AS c ON U.ID_CARGO = c.ID_CARGO INNER JOIN
                         dbo.Area AS A ON U.Id_Area = A.Id_Area INNER JOIN
                         dbo.Local AS L ON A.Id_Local = L.Id_Local INNER JOIN
                         dbo.Sede AS S ON L.Id_Sede =S.Id_Sede


END






