CREATE PROCEDURE [dbo].[pr_ListaUsuarios_2]

AS
BEGIN

SELECT        U.Id_Uusario AS ID,
 U.Nombre AS NOMBRE,
  U.ApePat AS APEPAT,
   U.ApeMat AS APEMAT,
    U.Telefono AS TELEFONO,
	 U.Email AS EMAIL,
	  U.Login AS LOGIN, 
                         U.Password AS PASSWORD, 
						 CASE u.Estado WHEN 1 THEN 'ACTIVO' ELSE 'INACTIVO' END AS ESTADO,
						 c.NOMBRE_CARGO AS CARGO
FROM            dbo.Usuario AS U INNER JOIN
                         dbo.CARGO AS c ON U.ID_CARGO = c.ID_CARGO where u.Estado=1


END






