/****** Objeto: StoredProcedure [dbo].[pr_MatenimientoArea] Fecha de script: 18/05/2026 10:08:31 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_MatenimientoArea]
@_Id_Area	int	=null,
@_Codigo_Area	varchar(6)	=null,
@_Descripcion_Area	varchar(max)	=null,
@_Nro_Piso	char(1)	=null,
@_Nro_Ambiente	varchar(3)	=null,
@_Id_Local	int	=null,

@Opcion char(1),

@pRpta int output,
@pMensaje varchar(100) output

AS
BEGIN
	 
     if (@Opcion='N')---Nuevo
	  begin 
	  
	      if EXISTS( select * from Area where Codigo_Area=@_Codigo_Area)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Codigo Area ya existe.'
				   return 0
			   End   
		    if EXISTS( select * from Area where Descripcion_Area=@_Descripcion_Area)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Nombre Area ya existe.'
				   return 0
			   End	           
	      
	  
	       insert into Area values(@_Codigo_Area,
		   @_Descripcion_Area,
		   @_Nro_Piso,
		   @_Nro_Ambiente,
		   @_Id_Local	       	   
	       )
	       if (@@RowCount=1) 
			   Begin
				set @pRpta=1
				set @pMensaje='Datos Area se a guardado satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0
				set @pMensaje='Datos Area no se a podido guardar.'
			   End
			   
      end
      else  if (@Opcion='M')
      Begin
           if EXISTS( select * from Area where Id_Area<>@_Id_Area and  Codigo_Area=@_Codigo_Area)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Codigo Area existe.'
				   return 0
			   End
	       if EXISTS( select * from Area where Id_Area<>@_Id_Area and  Descripcion_Area=@_Descripcion_Area)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Nombre Area existe.'
				   return 0
			   End

           update Area set Codigo_Area=@_Codigo_Area,
		   Descripcion_Area=@_Descripcion_Area,
		   Nro_Piso=@_Nro_Piso,
		   Nro_Ambiente=@_Nro_Ambiente,
		   Id_Local=@_Id_Local                            
								   where Id_Area=@_Id_Area
			if (@@RowCount=1) 
			   Begin
				set @pRpta=1
				set @pMensaje='Datos Area se a modificado satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0
				set @pMensaje='Datos Area no se a podido modificar.'
			   End
     End
     else  if (@Opcion='E')
      Begin
            
            BEGIN TRY
				delete from area where Id_Area=@_Id_Area
				if (@@RowCount=1) 
						   Begin
							    set @pRpta=1
							    set @pMensaje='Datos area se a eliminado satisfactorimente.'
						   End
					   else
						   Begin
							    set @pRpta=0
							     set @pMensaje='Los datos de area no se han podido eliminar.'
						   End
			END TRY
			BEGIN CATCH
				       Begin
							set @pRpta=0
							set @pMensaje='Sus datos no se puede eliminar porque esta siendo utilizado.'
					   End
			END CATCH;
			
			
     End


END





GO
