@_NOMBRE_CARGO	varchar(MAX)	=null,


@Opcion char(1),

@pRpta int output,
@pMensaje varchar(100) output

AS
BEGIN
	 
     if (@Opcion='N')---Nuevo
	  begin 
	  
	      if EXISTS( select * from CARGO where NOMBRE_CARGO=@_NOMBRE_CARGO)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Cargo ya existe.'
				   return 0
			   End           
	      
	  
	       insert into CARGO values(@_NOMBRE_CARGO	       	   
	       )
	       if (@@RowCount=1) 
			   Begin
				set @pRpta=1
				set @pMensaje='Datos cargo se a guardado satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0
				set @pMensaje='Datos cargo no se a podido guardar.'
			   End
			   
      end
      else  if (@Opcion='M')
      Begin
      
	           if EXISTS( select * from CARGO where ID_CARGO<>@_ID_CARGO and NOMBRE_CARGO=@_NOMBRE_CARGO)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Cargo existe.'
				   return 0
			   End

           update CARGO set NOMBRE_CARGO=@_NOMBRE_CARGO                            
								   where ID_CARGO=@_ID_CARGO
			if (@@RowCount=1) 
			   Begin
				set @pRpta=1
				set @pMensaje='Datos cargo se a modificado satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0
				set @pMensaje='Datos cargo no se a podido modificar.'
			   End
     End
     else  if (@Opcion='E')
      Begin
            
            BEGIN TRY
