@_GRUPO_TRABAJO	varchar(MAX) =NULL,

@Opcion char(1),

@pRpta int output,
@pMensaje varchar(100) output

AS
BEGIN
	 
     if (@Opcion='N')---Nuevo
	  begin 
	      if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where NRO_SERIE=@_NRO_SERIE AND NRO_SERIE<>'NINGUNO')
			   Begin
				   set @pRpta=0
				   set @pMensaje='Nro. serie elemento de configuracion ya existe.'
				   return 0
			   End
           if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where NRO_SERIE=@_NRO_SERIE AND
		             LOCALIZACION_FISICA = @_LOCALIZACION_FISICA)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Elemento de configuracion ya existe.'
				   return 0
			   End
           if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where IP=@_IP AND
		             LOCALIZACION_FISICA = @_LOCALIZACION_FISICA)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Direccion IP ya existe.'
				   return 0
			   End 

			   --EL GATEWAY SI SE PUEDE REPETIR 

		    --if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where GATEWAY=@_GATEWAY AND
		    --         LOCALIZACION_FISICA = @_LOCALIZACION_FISICA)
			   --Begin
				  -- set @pRpta=0
				  -- set @pMensaje='Direccion Gateway ya existe.'
				  -- return 0
			   --End  	    
	       insert into ELEMENTOS_CONFIGURACION values(@_NOMBRE_ELEMENTO_CONFIGURACION
	       ,@_ID_TIPO
	       ,@_ID_ESTADO	       
	       ,@_PROPIETARIO
	       ,@_ID_DESCRIPCION
		   ,@_ID_IMP_ELE_CONF_HAR
		   ,@_LOCALIZACION_FISICA
		   ,getdate()
		   ,@_RESPONSABLE_REGISTRO
		   ,@_NIVEL_PRIORIDAD
		   ,@_NRO_SERIE
		   ,@_FABRICANTE_O_PROVEEDOR
		   ,@_ID_MAR
		   ,@_ID_MOD
		   ,@_IP
		   ,@_GATEWAY
		   ,@_GRUPO_TRABAJO
		   )
	       if (@@RowCount=1) 
