				set @pRpta=0
				set @pMensaje='Datos ELEMENTO CONFIGURACION no se a podido guardar.'
			   End
			   
      end
      else  if (@Opcion='M')
      Begin

             if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where ID_ELEMENTO_CONFIGURACION<>@_ID_ELEMENTO_CONFIGURACION AND NRO_SERIE=@_NRO_SERIE AND NRO_SERIE<>'NINGUNO')
			   Begin
				   set @pRpta=0
				   set @pMensaje='Nro. serie elemento de configuracion ya existe.'
				   return 0
			   End   
            if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where ID_ELEMENTO_CONFIGURACION<>@_ID_ELEMENTO_CONFIGURACION AND NOMBRE_ELEMENTO_CONFIGURACION=@_NOMBRE_ELEMENTO_CONFIGURACION AND
		             LOCALIZACION_FISICA = @_LOCALIZACION_FISICA)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Elemento de configuracion ya existe.'
				   return 0
			   End
	        if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where ID_ELEMENTO_CONFIGURACION<>@_ID_ELEMENTO_CONFIGURACION AND IP=@_IP AND
		             LOCALIZACION_FISICA = @_LOCALIZACION_FISICA AND IP<>'NINGUNO')
			   Begin
				   set @pRpta=0
				   set @pMensaje='Direccion IP ya existe.'
				   return 0
			   End

			   -- el GATEWAY SI SE PUEDE REPETIR EL IP

      --      if EXISTS( select * from dbo.ELEMENTOS_CONFIGURACION where ID_ELEMENTO_CONFIGURACION<>@_ID_ELEMENTO_CONFIGURACION AND GATEWAY=@_GATEWAY AND
		    --         LOCALIZACION_FISICA = @_LOCALIZACION_FISICA AND GATEWAY<>'NINGUNO')
			   --Begin
				  -- set @pRpta=0
				  -- set @pMensaje='Direccion Gateway ya existe.'
				  -- return 0
			   --End
	           

           update dbo.ELEMENTOS_CONFIGURACION set NOMBRE_ELEMENTO_CONFIGURACION=@_NOMBRE_ELEMENTO_CONFIGURACION,
                                   ID_TIPO=@_ID_TIPO,
                                   ID_ESTADO=@_ID_ESTADO,
                                   PROPIETARIO=@_PROPIETARIO,
                                   ID_DESCRIPCION=@_ID_DESCRIPCION,
								   ID_IMP_ELE_CONF_HAR=@_ID_IMP_ELE_CONF_HAR,
								   LOCALIZACION_FISICA=@_LOCALIZACION_FISICA,
								   FECHA_REGISTRO=GETDATE(),
								   RESPONSABLE_REGISTRO=@_RESPONSABLE_REGISTRO, 
								   ID_NIVEL=@_NIVEL_PRIORIDAD,
								   NRO_SERIE=@_NRO_SERIE,
								   FABRICANTE_O_PROVEEDOR=@_FABRICANTE_O_PROVEEDOR,
								   ID_MAR=@_ID_MAR,
								   ID_MOD=@_ID_MOD,
								   IP=@_IP,
