@_Login	        varchar(50)=null,
@_Password	    varchar(50)=null,
@_Estado	    bit=null,
@_Id_Cargo	    int=null,
@_Id_Area	int=null,

@Opcion char(1),

@pRpta int output,
@pMensaje varchar(100) output

AS
BEGIN
	 
     if (@Opcion='N')---Nuevo
	  begin 
	  
	      if EXISTS( select * from dbo.Usuario where Telefono=@_Telefono)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Nro. telefono ya existe.'
				   return 0
			   End
	           
	      if EXISTS( select * from dbo.Usuario where Email=@_Email)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Email ya existe.'
				   return 0
			   End
			   
			   
		   if EXISTS( select * from dbo.Usuario where Login=@_Login)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Login ya existe.'
				   return 0
			   End
			   
		   if EXISTS( select * from dbo.Usuario where Password=@_Password)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Password ya existe.'
				   return 0
			   End		   	       
	  
	       insert into Usuario values(@_Nombre
	       ,@_ApePat
	       ,@_ApeMat	       
	       ,@_Telefono
	       ,@_Email
		   ,@_Login
		   ,@_Password
		   ,@_Estado
		   ,@_Id_Cargo
		   ,@_Id_Area		   
	       )
	       if (@@RowCount=1) 
			   Begin
				set @pRpta=1
				set @pMensaje='Datos del usuario se a guardado satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0
				set @pMensaje='Datos del usuario no se a podido guardar.'
			   End
			   
      end
      else  if (@Opcion='M')
      Begin
      
               
            
	
	           if EXISTS( select * from dbo.Usuario where Id_Uusario<>@_Id_Uusario and Telefono=@_Telefono)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Nro. telefono ya existe.'
				   return 0
			   End
	           
	          
	           if EXISTS( select * from dbo.Usuario where  Id_Uusario<>@_Id_Uusario and Email=@_Email)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Email ya existe.'
				   return 0
			   End
			   
			   if EXISTS( select * from dbo.Usuario where  Id_Uusario<>@_Id_Uusario and Login=@_Login)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Login ya existe.'
				   return 0
			   End  
			   
			   if EXISTS( select * from dbo.Usuario where  Id_Uusario<>@_Id_Uusario and Password=@_Password)
			   Begin
				   set @pRpta=0
				   set @pMensaje='Password ya existe.'
				   return 0
			   End 

           update dbo.Usuario set  Nombre=@_Nombre,
                                   ApePat=@_ApePat,
                                   ApeMat=@_ApeMat,
                                   Telefono=@_Telefono,
                                   Email=@_Email,
								   Login=@_Login,
								   Password=@_Password,
								   Estado=@_Estado,
								   ID_CARGO=@_Id_Cargo,
								   Id_Area=@_Id_Area                                 
								   where Id_Uusario=@_Id_Uusario
			if (@@RowCount=1) 
			   Begin
				set @pRpta=1
				set @pMensaje='Datos del usuario se a modificado satisfactorimente.'
			   End
			else
			   Begin
				set @pRpta=0
				set @pMensaje='Datos del usuario no se a podido modificar.'
			   End
     End
     else  if (@Opcion='E')
      Begin
            
            BEGIN TRY
				delete from dbo.Usuario where  Id_Uusario=@_Id_Uusario
				if (@@RowCount=1) 
						   Begin
							    set @pRpta=1
							    set @pMensaje='Datos del usuario se a eliminado satisfactorimente.'
						   End
					   else
						   Begin
							    set @pRpta=0
							     set @pMensaje='Los datos usuario no se han podido eliminar.'
						   End
			END TRY
			BEGIN CATCH
				       Begin
							set @pRpta=0
							set @pMensaje='Sus datos no se puede eliminar porque esta siendo utilizado.'
					   End
			END CATCH;
			
			
     End


END





