		WHERE        (dbo.Local.Id_Local = @Codigo_Local)
  end
else
  begin
		SELECT        dbo.Area.Id_Area AS CODIGO, dbo.Area.Descripcion_Area AS NOMBRE
		FROM            dbo.Local INNER JOIN
								 dbo.Area ON dbo.Local.Id_Local = dbo.Area.Id_Local
		
  end



END

