CREATE PROCEDURE [dbo].[pr_Obtener_Areas_2]

AS
BEGIN


SELECT        dbo.Area.Id_Area AS ID, dbo.Sede.Descripcion_Sede AS SEDE, dbo.Local.Nombre_Local AS LOCAL, dbo.Ubigeo.Distrito AS DISTRITO, dbo.Ubigeo.Provincia AS PROVINCIA, 
                         dbo.Ubigeo.Departamento AS DEPARTAMENTO, dbo.Local.Direccion_Local AS [DIRECCION LOCAL], 
