SELECT        EC.ID_ELEMENTO_CONFIGURACION AS [ID CI], EC.NOMBRE_ELEMENTO_CONFIGURACION AS [NOMBRE CI], TEC.NOMBRE_TIPO AS [TIPO CI], EEC.NOMBRE_ESTADO AS [ESTADO CI], 
                         P.Nombre_Personal + ' ' + P.ApePat_Personal + ' ' + P.ApeMat_Personal AS PROPIETARIO, DEC.NOMBRE_DESCRIPCION AS [DESCRIPCION CI], S.Descripcion_Sede AS SEDE, L.Nombre_Local AS LOCAL, 
