CREATE PROCEDURE [dbo].[pr_Reporte_CIS_Relacionados_Con_Otros_CIS]
@PADRE_CI					varchar(max)=null,
@PADRE_TIPO_CI					varchar(max)=null,
@PADRE_ESTADO_CI     varchar(max)=null,
@PADRE_PROPIETARIO_CI     varchar(max)=null,
@PADRE_DESCRIPCION_CI     varchar(max)=null,
@PADRE_SEDE     varchar(max)=null,
@PADRE_LOCAL     varchar(max)=null,
@PADRE_AREA     varchar(max)=null


AS
BEGIN
	 
    select * from [dbo].[VISTA_RELACION_ELEMENTOS_CONFIGURACION]
	WHERE ([PADRE CI]='' or [PADRE CI] LIKE '%' +  @PADRE_CI + '%') AND
	([PADRE TIPO CI]='' or [PADRE TIPO CI] LIKE '%' +  @PADRE_TIPO_CI + '%') AND
	([PADRE ESTADO CI]='' or [PADRE ESTADO CI] LIKE '%' +  @PADRE_ESTADO_CI + '%') AND
	([PADRE PROPIETARIO CI]='' or [PADRE PROPIETARIO CI]  LIKE '%' +  @PADRE_PROPIETARIO_CI + '%') AND
	([PADRE DESCRIPCION CI]='' or [PADRE DESCRIPCION CI]  LIKE '%' +  @PADRE_DESCRIPCION_CI + '%') AND
	([PADRE SEDE]='' or [PADRE SEDE]  LIKE '%' +  @PADRE_SEDE + '%') AND
	([PADRE LOCAL]='' or [PADRE LOCAL]  LIKE '%' +  @PADRE_LOCAL + '%') AND
	([PADRE AREA]='' or [PADRE AREA]  LIKE '%' +  @PADRE_AREA + '%')
	order by [PADRE DESCRIPCION CI] asc



