/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_ReporteElementosConfiguracion]
@NOMBRE_CI					varchar(max)=null,
@TIPO_CI					varchar(max)=null,
@ESTADO_CI					varchar(max)=null,
@PROPIETARIO_CI					varchar(max)=null,
@DESCRIPCION_CI					varchar(max)=null,
@IMPACTO_CI					varchar(max)=null,
@SEDE				varchar(max)=null,
@OCAL				varchar(max)=null,
@AREA				varchar(max)=null,
@RESPONSABLE				varchar(max)=null,
@NIVEL_PRIORIDAD varchar(max)=null,
@MARCA varchar(max)=null,
@MODELO varchar(max)=null,
@FECHA_INICIO_CREACION_CI	varchar(max)=null,
@FECHA_FIN_CREACION_CI	    varchar(max)=null


AS
BEGIN
	 
    select * from [dbo].[VISTA_REPORTE_ELEMENTOS_CONFIGURACION]
	WHERE   ([NOMBRE CI]='' or [NOMBRE CI] LIKE '%' +  @NOMBRE_CI + '%') AND
	([NOMBRE TIPO CI]='' or [NOMBRE TIPO CI] LIKE '%' +  @TIPO_CI + '%') and
	([ESTADO CI]='' or [ESTADO CI]LIKE '%' +  @ESTADO_CI + '%') and
	(PROPIETARIO='' or PROPIETARIO LIKE '%' +  @PROPIETARIO_CI + '%') and
	([DESCRIPCION CI]='' or [DESCRIPCION CI] LIKE '%' +  @DESCRIPCION_CI + '%') and
	([IMPACTO CI]='' or [IMPACTO CI] LIKE '%' +  @IMPACTO_CI + '%') and
	(SEDE='' or SEDE LIKE '%' +  @SEDE + '%') and
	(LOCAL='' or LOCAL LIKE '%' +  @OCAL + '%') AND
	(AREA='' or AREA LIKE '%' +  @AREA + '%') AND
	(RESPONSABLE='' or RESPONSABLE LIKE '%' +  @RESPONSABLE + '%') AND
	([NIVEL PRIORIDAD]='' or [NIVEL PRIORIDAD] like @NIVEL_PRIORIDAD + '%' ) and
	(MARCA='' or MARCA like @MARCA + '%' ) and
	(MODELO='' or MODELO like @MODELO + '%' ) and
	--( ( ([FEC. CREACION CI] >= CAST(@FECHA_INICIO_CREACION_CI AS datetime)) and [FEC. CREACION CI] <= CAST(@FECHA_FIN_CREACION_CI AS datetime)) OR @FECHA_INICIO_CREACION_CI='' OR @FECHA_FIN_CREACION_CI='')
	( ( (CONVERT(DATETIME,CONVERT(VARCHAR(11), [FEC. CREACION CI])) >= CAST(@FECHA_INICIO_CREACION_CI AS datetime)) and CONVERT(DATETIME,CONVERT(VARCHAR(11), [FEC. CREACION CI])) <= CAST(@FECHA_FIN_CREACION_CI AS datetime)) OR @FECHA_INICIO_CREACION_CI='' OR @FECHA_FIN_CREACION_CI='') 

END

