GO
/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_ReporteSeguimientoElementosConfiguracion]
@Nombre_CI					    varchar(max)=null,
@Tipo_CI					    varchar(max)=null,
@Nro_Serie					    varchar(max)=null,
@Descripcion_CI				varchar(max)=null,
@Sede					    varchar(max)=null,
@Local					    varchar(max)=null,
@Area					    varchar(max)=null,
@Responsable                varchar(max)=null,
@Clasificacion_Datos        varchar(max)=null,
@Relacion_otros_CIs         varchar(max)=null,
@FECHA_INICIO_SEGUIMIENTO	varchar(max)=null,
@FECHA_FIN_SEGUIMIENTO	    varchar(max)=null,
@ESTADO_ACTUAL_CIS  varchar(max)=null


AS
BEGIN
	if(LTRIM(RTRIM(@FECHA_INICIO_SEGUIMIENTO))='' and LTRIM(RTRIM(@FECHA_FIN_SEGUIMIENTO))='')
	   begin
		select * from [dbo].[VISTA_SEGUIMIENTO_DETALLE_ELEMENTO_CONFIGURACION] 
		WHERE ([NOMBRE CI]='' or [NOMBRE CI] LIKE '%' +  @Nombre_CI + '%') and
		([TIPO CI]='' or [TIPO CI] LIKE '%' +  @Tipo_CI + '%') and
		([NRO. SERIE]='' or [NRO. SERIE] LIKE '%' +  @Nro_Serie + '%') and
		([DESCRIPCION CI]='' or [DESCRIPCION CI] LIKE '%' +  @Descripcion_CI + '%') and
		(SEDE='' or SEDE LIKE '%' +  @Sede + '%') and
		(LOCAL='' or LOCAL LIKE '%' +  @Local + '%') and
		(AREA='' or AREA LIKE '%' +  @Area + '%') and
		(RESPONSABLE='' or RESPONSABLE LIKE '%' +  @Responsable + '%') and
		([CLASIFICACION DATOS]='' or [CLASIFICACION DATOS] LIKE '%' +  @Clasificacion_Datos + '%') and
		([RELACION CIS]='' or [RELACION CIS] LIKE '%' +  @Relacion_otros_CIs + '%') AND
		( ( ([FECHA SEGUIMIENTO] >= CAST(@FECHA_INICIO_SEGUIMIENTO AS datetime)) and [FECHA SEGUIMIENTO] <= CAST(@FECHA_FIN_SEGUIMIENTO AS datetime)) OR @FECHA_INICIO_SEGUIMIENTO='' OR @FECHA_FIN_SEGUIMIENTO='') AND
		([ESTADO ACTUAL]='' or [ESTADO ACTUAL] LIKE '%' +  @ESTADO_ACTUAL_CIS + '%') and
		(CONVERT(DATETIME, CONVERT(VARCHAR(11), [FECHA SEGUIMIENTO])) = CONVERT(DATETIME, 
                         CONVERT(VARCHAR(11), GETDATE())))
		order by [NOMBRE CI] , [TIPO CI] asc
	  end
    else if(LTRIM(RTRIM(@FECHA_INICIO_SEGUIMIENTO))!='' and LTRIM(RTRIM(@FECHA_FIN_SEGUIMIENTO))!='')
	  begin
	    select * from [dbo].[VISTA_SEGUIMIENTO_DETALLE_ELEMENTO_CONFIGURACION] 
		WHERE ([NOMBRE CI]='' or [NOMBRE CI] LIKE '%' +  @Nombre_CI + '%') and
		([TIPO CI]='' or [TIPO CI] LIKE '%' +  @Tipo_CI + '%') and
		([NRO. SERIE]='' or [NRO. SERIE] LIKE '%' +  @Nro_Serie + '%') and
		([DESCRIPCION CI]='' or [DESCRIPCION CI] LIKE '%' +  @Descripcion_CI + '%') and
		(SEDE='' or SEDE LIKE '%' +  @Sede + '%') and
		(LOCAL='' or LOCAL LIKE '%' +  @Local + '%') and
		(AREA='' or AREA LIKE '%' +  @Area + '%') and
		(RESPONSABLE='' or RESPONSABLE LIKE '%' +  @Responsable + '%') and
		([CLASIFICACION DATOS]='' or [CLASIFICACION DATOS] LIKE '%' +  @Clasificacion_Datos + '%') and
		([RELACION CIS]='' or [RELACION CIS] LIKE '%' +  @Relacion_otros_CIs + '%') AND
		( ( (CONVERT(DATETIME,CONVERT(VARCHAR(11), [FECHA SEGUIMIENTO])) >= CAST(@FECHA_INICIO_SEGUIMIENTO AS datetime)) and CONVERT(DATETIME,CONVERT(VARCHAR(11), [FECHA SEGUIMIENTO])) <= CAST(@FECHA_FIN_SEGUIMIENTO AS datetime)) OR @FECHA_INICIO_SEGUIMIENTO='' OR @FECHA_FIN_SEGUIMIENTO='') AND
		([ESTADO ACTUAL]='' or [ESTADO ACTUAL] LIKE '%' +  @ESTADO_ACTUAL_CIS + '%') 
		order by [NOMBRE CI] , [TIPO CI] asc 
	  end
END





GO
