/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_Verificar_Acceso_Sistema_Personal]
@LOGIN_USUARIO	    varchar(MAX),
@PASSWORD_USUARIO	varchar(MAX)
AS
BEGIN

SELECT        U.Id_Uusario AS ID, U.Nombre AS NOMBRE, U.ApePat AS APEPAT, U.ApeMat AS APEMAT, U.Telefono AS TELEFONO, U.Email AS EMAIL, U.Login AS LOGIN, 
                         U.Password AS PASSWORD, CASE u.Estado WHEN 1 THEN 'ACTIVO' ELSE 'INACTIVO' END AS ESTADO, C.NOMBRE_CARGO AS CARGO, 
                         S.Descripcion_Sede AS SEDE, L.Nombre_Local AS [NOMBRE LOCAL], L.Direccion_Local AS [DIRECCION LOCAL], 
                         UU.Departamento + ' / ' + UU.Provincia + ' / ' + UU.Distrito AS UBICACION, L.Telefono_local AS [TELEFONO LOCAL], 
                         L.Pagnia_Web_Local AS [PAGINA WEB LOCAL], L.Email_Local AS [EMAIL LOCAL], L.Total_CIS_Local AS [TOTAL CIS LOCAL]
FROM            dbo.Usuario AS U INNER JOIN
                         dbo.CARGO AS C ON U.ID_CARGO = C.ID_CARGO INNER JOIN
                         dbo.Area AS A ON U.Id_Area = A.Id_Area INNER JOIN
                         dbo.Local AS L ON A.Id_Local = L.Id_Local INNER JOIN
                         dbo.Sede AS S ON L.Id_Sede = S.Id_Sede INNER JOIN
                         dbo.Ubigeo AS UU ON L.Cod_Ubi = UU.Cod_Ubi
WHERE Login = rtrim(ltrim(@LOGIN_USUARIO)) and Password = rtrim(ltrim(@PASSWORD_USUARIO)) and ESTADO=1





END






GO
/****** Objeto: StoredProcedure [dbo].[pr_VERIFICAR_PERMISO_ACCESO_PAGINA_WEB] Fecha de script: 18/05/2026 10:08:31 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_VERIFICAR_PERMISO_ACCESO_PAGINA_WEB]
@_ID_USUARIO	int	=null,
@_PAGINA_WEB	VARCHAR(MAX)	=null
AS
BEGIN



IF EXISTS(	   SELECT        dbo.autorizacion.aprobacion_autorizacion
FROM            dbo.Usuario INNER JOIN
                         dbo.autorizacion ON dbo.Usuario.Id_Uusario = dbo.autorizacion.IDPer INNER JOIN
                         dbo.formulario ON dbo.autorizacion.id_formulario = dbo.formulario.id_formulario INNER JOIN
                         dbo.permiso ON dbo.autorizacion.id_autorizacion = dbo.permiso.id_autorizacion INNER JOIN
                         dbo.derecho ON dbo.permiso.id_derecho = dbo.derecho.id_derecho
WHERE        (dbo.formulario.nombre_formulario = @_PAGINA_WEB) AND (dbo.Usuario.Id_Uusario = @_ID_USUARIO)
GROUP BY dbo.autorizacion.aprobacion_autorizacion)
BEGIN
   SELECT 'true' as RPTA
END
else
BEGIN
   SELECT 'false' as RPTA
END
		






	  
END





GO
/****** Objeto: StoredProcedure [dbo].[pr_VERIFICAR_PERMISOS_DERECHOS_ACCESO_PAGINA_WEB] Fecha de script: 18/05/2026 10:08:31 ******/
SET ANSI_NULLS ON
