SET QUOTED_IDENTIFIER ON
GO
/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[pr_VERIFICAR_PERMISOS_DERECHOS_ACCESO_PAGINA_WEB]
@_ID_USUARIO	int	=null,
@_PAGINA_WEB	VARCHAR(MAX)	=null,
@_DERECHO	VARCHAR(MAX)	=null
AS
BEGIN



IF EXISTS(	   SELECT        dbo.Usuario.Id_Uusario, dbo.formulario.nombre_formulario, dbo.derecho.nombre_derecho, dbo.permiso.aprobacion_permiso
FROM            dbo.Usuario INNER JOIN
                         dbo.autorizacion ON dbo.Usuario.Id_Uusario = dbo.autorizacion.IDPer INNER JOIN
                         dbo.formulario ON dbo.autorizacion.id_formulario = dbo.formulario.id_formulario INNER JOIN
                         dbo.permiso ON dbo.autorizacion.id_autorizacion = dbo.permiso.id_autorizacion INNER JOIN
                         dbo.derecho ON dbo.permiso.id_derecho = dbo.derecho.id_derecho
WHERE        (dbo.formulario.nombre_formulario = @_PAGINA_WEB) AND (dbo.derecho.nombre_derecho = @_DERECHO) AND (dbo.Usuario.Id_Uusario = @_ID_USUARIO))
BEGIN
   SELECT 'true' as RPTA
END
else
BEGIN
   SELECT 'false' as RPTA
END
		






	  
END





