/****** Objeto: StoredProcedure [dbo].[prNro_Total_CIs_registrados_relativos_a_servicios_TI_CMDB.] Fecha de script: 18/05/2026 10:08:31 ******/
SET ANSI_NULLS ON
GO
SET QUOTED_IDENTIFIER ON
GO
/****** Object:  StoredProcedure [dbo].[pr_ObtenerListaColores]    Script Date: 03/01/2014 19:29:23 ******/
CREATE PROCEDURE [dbo].[prNro_Total_CIs_registrados_relativos_a_servicios_TI_CMDB.]

AS
BEGIN



SELECT        COUNT(dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO) AS [NRO TOTAL CIS RELATIVO A SERVICIOS]
FROM            dbo.ELEMENTOS_CONFIGURACION INNER JOIN
                         dbo.[DESCRIPCION_ELEMENTO CONFIGURACION] ON 
                         dbo.ELEMENTOS_CONFIGURACION.ID_DESCRIPCION = dbo.[DESCRIPCION_ELEMENTO CONFIGURACION].ID_DESCRIPCION INNER JOIN
                         dbo.TIPOS_ELEMENTO_CONFIGURACION ON dbo.ELEMENTOS_CONFIGURACION.ID_TIPO = dbo.TIPOS_ELEMENTO_CONFIGURACION.ID_TIPO AND 
                         dbo.[DESCRIPCION_ELEMENTO CONFIGURACION].ID_TIPO = dbo.TIPOS_ELEMENTO_CONFIGURACION.ID_TIPO
WHERE        (dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO = 'DISPOSITIVOS DE RED') OR
                         (dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO = 'BASE DE DATOS') OR
                         (dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO = 'APLICACIONES') OR
                         (dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO = 'SISTEMAS OPERATIVOS') OR
                         (dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO = 'SERVIDORES') OR
                         (dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO = 'EDUIPOS DE ESCRITORIO') OR
                         (dbo.TIPOS_ELEMENTO_CONFIGURACION.NOMBRE_TIPO = 'ADMINISTRADORES DE BASE DE DATOS')
		



	  
END





